    for (let p = 1; p < nums.length - 2; p++) {
        for (let q = p + 1; q < nums.length - 1; q++) {
            // Check if nums[0...p] is strictly increasing
            let increasing = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    increasing = false;
                    break;
                }
            }
            if (!increasing) continue;

            // Check if nums[p...q] is strictly decreasing
            increasing = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    increasing = false;
                    break;
                }
            }
            if (!increasing) continue;

            // Check if nums[q...n-1] is strictly increasing
            increasing = true;
            for (let i = q; i < nums.length - 1; i++) {
                if (nums[i] >= nums[i + 1]) {
                    increasing = false;
                    break;
                }
            }
            if (increasing) {
                return true;
            }
        }
    }
    return false;
}
